// =============================================================================
// Worn Mask DL Loaders (for Link wearing mask on face)
// =============================================================================
// These DLs are DIFFERENT from Get Item DLs!
// Get Item: object_gi_* files (spinning 3D model when receiving)
// Worn: gameplay_keep or object_mask_* (attached to Link's face)

void* MmAssets_LoadDekuMaskWornDL(void) {
    if (!MmAssets_IsAvailable()) {
        return nullptr;
    }
    MMASSETS_LOG("[MM Assets] Loading Deku Mask WORN DL: %s", MM_DEKU_MASK_WORN_DL_PATH);
    return (void*)MM_DEKU_MASK_WORN_DL_PATH;
}

