// =============================================================================
// MM SFX System - Direct Audio Bypass
// =============================================================================
// Decodes MM ADPCM samples to PCM and mixes directly into OOT's audio output.
// This bypasses OOT's entire SFX pipeline (which caches sound data at startup
// and cannot play injected samples during gameplay).
//
// Architecture:
//   Game thread: MmSfx_PlayAtPos() → decode ADPCM → add to playing list
//   Audio thread: MmDirectAudio_MixInto() → mix PCM into output buffer
// =============================================================================

// MM SFX ID macros (matching OOT's z64audio.h SFX_INDEX)
#define MM_SFX_BANK_SHIFT 12
#define MM_SFX_INDEX_MASK 0x03FF
#define MM_SFX_BANK_INDEX(sfxId) (((sfxId) >> MM_SFX_BANK_SHIFT) & 0xF)
#define MM_SFX_SOUND_INDEX(sfxId) ((sfxId)&MM_SFX_INDEX_MASK)

// MM Goron SFX IDs
#define MM_NA_SE_PL_GORON_ROLL 0x0990
#define MM_NA_SE_PL_GORON_BALL_CHARGE 0x08EB
#define MM_NA_SE_SY_TRANSFORM_MASK_FLASH 0x4835

#define MM_SFX_MAX_FONTS 16
#define MM_SFX_FONT_PATH_FMT "audio/fonts/Soundfont_%d"

// MM SFX sequence (NA_BGM_GENERAL_SFX) uses soundfont 0 as the main SFX font for all banks.
// Soundfont 0 contains both soundEffects[] (for banks 0-5) and drums[] (for voice bank 6).
static const s32 sMmBankToFontMap[] = { 0, 0, 0, 0, 0, 0, 0 };

// --- Font cache ---
typedef struct {
    s32 fontId;
    SoundFont* font;
    size_t sizeBytes;
} MmSfxCacheEntry;

static MmSfxCacheEntry sSfxCache[MM_SFX_MAX_FONTS];
static s32 sSfxCacheCount = 0;
static s32 sSfxInitialized = 0;
static f32 sTempFreqScale = 1.0f;

static void MmSfxCache_Init(void) {
    if (sSfxInitialized)
        return;
    for (s32 i = 0; i < MM_SFX_MAX_FONTS; i++) {
        sSfxCache[i].fontId = -1;
        sSfxCache[i].font = nullptr;
        sSfxCache[i].sizeBytes = 0;
    }
    sSfxCacheCount = 0;
    sSfxInitialized = 1;
}

static MmSfxCacheEntry* MmSfxCache_Find(s32 fontId) {
    for (s32 i = 0; i < sSfxCacheCount; i++) {
        if (sSfxCache[i].fontId == fontId)
            return &sSfxCache[i];
    }
    return nullptr;
}

static MmSfxCacheEntry* MmSfxCache_GetFree(void) {
    if (sSfxCacheCount < MM_SFX_MAX_FONTS)
        return &sSfxCache[sSfxCacheCount++];
    for (s32 i = 0; i < MM_SFX_MAX_FONTS - 1; i++)
        sSfxCache[i] = sSfxCache[i + 1];
    sSfxCacheCount = MM_SFX_MAX_FONTS - 1;
    return &sSfxCache[sSfxCacheCount++];
}

s32 MmSfx_IsAvailable(void) {
    return MmAssets_IsAvailable();
}

void MmSfx_Init(void) {
    MmSfxCache_Init();
}

void MmSfx_Shutdown(void) {
    MmDirectAudio_StopAll();
    MmSfx_FlushCache();
    sSfxInitialized = 0;
}

SoundFont* MmSfx_LoadFont(s32 fontId) {
    if (!sSfxInitialized)
        MmSfxCache_Init();
    if (fontId < 0 || fontId >= 7)
        return nullptr;
    if (!MmAssets_IsAvailable())
        return nullptr;

    MmSfxCacheEntry* cached = MmSfxCache_Find(fontId);
    if (cached && cached->font)
        return cached->font;

    char path[64];
    snprintf(path, sizeof(path), MM_SFX_FONT_PATH_FMT, fontId);

    size_t size = 0;
    void* resource = MmAssets_LoadFromMmArchive(path, &size);
    if (!resource) {
        MMSFX_LOG("[MmSfx] LoadFont FAIL: %s not found in mm.o2r", path);
        return nullptr;
    }

    SoundFont* font = static_cast<SoundFont*>(resource);
    MMSFX_LOG("[MmSfx] LoadFont(%d) OK: %u sfx, %u drums", fontId, font->numSfx, font->numDrums);

    MmSfxCacheEntry* entry = MmSfxCache_GetFree();
    if (entry) {
        entry->fontId = fontId;
        entry->font = font;
        entry->sizeBytes = size;
    }
    return font;
}

SoundFont* MmSfx_GetFontForSfx(u16 sfxId) {
    s32 bank = MM_SFX_BANK_INDEX(sfxId);
    if (bank < 0 || bank >= 7)
        return nullptr;
    return MmSfx_LoadFont(sMmBankToFontMap[bank]);
}

// =============================================================================
// Direct Audio: ADPCM Decoder
// =============================================================================
// Decodes N64 VADPCM (codec 0) and SMALL_ADPCM (codec 3) to s16 PCM.
// Algorithm: Block-based prediction using codebook (order=2, 8-sample sub-frames).

#define VADPCM_FRAME_ADPCM 9       // codec 0: 1 header + 8 data bytes
#define VADPCM_FRAME_SMALL_ADPCM 5 // codec 3: 1 header + 4 data bytes
#define VADPCM_SAMPLES_PER_FRAME 16

// Decode one ADPCM frame (16 samples)
// Algorithm matches soh/soh/mixer.c aADPCMdecImpl() exactly
static void MmDirectAudio_DecodeFrame(const u8* frame, s32 frameSize, s16* out, const s16* book, s32 order, s16* hist) {
    s32 shift = frame[0] >> 4;
    s32 pred = frame[0] & 0xF;
    const s16* tbl0 = &book[pred * order * 8];     // coefs for prev2
    const s16* tbl1 = &book[pred * order * 8 + 8]; // coefs for prev1
    const u8* data = &frame[1];

    // Extract and scale input nibbles per sub-frame (matching mixer.c)
    for (s32 half = 0; half < 2; half++) {
        s16 ins[8];
        s16 prev1 = hist[1]; // most recent
        s16 prev2 = hist[0]; // second most recent

        if (frameSize == VADPCM_FRAME_SMALL_ADPCM) {
            // codec 3: 2 bits per sample, 2 bytes per sub-frame
            const u8* p = &data[half * 2];
            for (s32 j = 0; j < 2; j++) {
                ins[j * 4] = (s16)(((s32)(p[j] >> 6) << 30) >> 30) << shift;
                ins[j * 4 + 1] = (s16)((((s32)(p[j] >> 4) & 0x3) << 30) >> 30) << shift;
                ins[j * 4 + 2] = (s16)((((s32)(p[j] >> 2) & 0x3) << 30) >> 30) << shift;
                ins[j * 4 + 3] = (s16)((((s32)(p[j]) & 0x3) << 30) >> 30) << shift;
            }
        } else {
            // codec 0: 4 bits per sample, 4 bytes per sub-frame
            const u8* p = &data[half * 4];
            for (s32 j = 0; j < 4; j++) {
                ins[j * 2] = (s16)(((s32)(p[j] >> 4) << 28) >> 28) << shift;
                ins[j * 2 + 1] = (s16)((((s32)(p[j]) & 0xF) << 28) >> 28) << shift;
            }
        }

        // Core prediction loop - RECURSIVE within sub-frame (matching mixer.c:220-227)
        for (s32 j = 0; j < 8; j++) {
            s32 acc = tbl0[j] * prev2 + tbl1[j] * prev1 + ((s32)ins[j] << 11);
            for (s32 k = 0; k < j; k++) {
                acc += tbl1[((j - k) - 1)] * ins[k];
            }
            acc >>= 11;
            if (acc > 32767)
                acc = 32767;
            if (acc < -32768)
                acc = -32768;
            out[half * 8 + j] = (s16)acc;
        }

        // Update history for next sub-frame
        hist[0] = out[half * 8 + 6]; // second most recent
        hist[1] = out[half * 8 + 7]; // most recent
    }
}

// Decode entire ADPCM sample to PCM buffer
static s16* MmDirectAudio_DecodeADPCM(SoundFontSample* sample, u32* outLength) {
    if (!sample || !sample->sampleAddr || sample->size == 0)
        return nullptr;

    s32 frameSize;
    switch (sample->codec) {
        case 0:
            frameSize = VADPCM_FRAME_ADPCM;
            break;
        case 3:
            frameSize = VADPCM_FRAME_SMALL_ADPCM;
            break;
        default:
            MMSFX_LOG("[MmDirectAudio] Unsupported codec %d", sample->codec);
            return nullptr;
    }

    if (!sample->book || !sample->book->book) {
        MMSFX_LOG("[MmDirectAudio] No codebook for sample");
        return nullptr;
    }

    u32 numFrames = sample->size / frameSize;
    u32 totalSamples = numFrames * VADPCM_SAMPLES_PER_FRAME;

    // Limit to loop end if looping
    if (sample->loop && sample->loop->loopEnd > 0 && sample->loop->loopEnd < totalSamples) {
        totalSamples = sample->loop->loopEnd;
        numFrames = (totalSamples + VADPCM_SAMPLES_PER_FRAME - 1) / VADPCM_SAMPLES_PER_FRAME;
    }

    s16* pcm = (s16*)malloc(totalSamples * sizeof(s16));
    if (!pcm)
        return nullptr;

    s16 hist[2] = { 0, 0 };
    const u8* src = (const u8*)sample->sampleAddr;
    s32 order = sample->book->order;
    const s16* book = sample->book->book;

    for (u32 f = 0; f < numFrames; f++) {
        s16 frameBuf[VADPCM_SAMPLES_PER_FRAME];
        MmDirectAudio_DecodeFrame(&src[f * frameSize], frameSize, frameBuf, book, order, hist);

        u32 dstOffset = f * VADPCM_SAMPLES_PER_FRAME;
        u32 count = VADPCM_SAMPLES_PER_FRAME;
        if (dstOffset + count > totalSamples) {
            count = totalSamples - dstOffset;
        }
        memcpy(&pcm[dstOffset], frameBuf, count * sizeof(s16));
    }

    *outLength = totalSamples;
    return pcm;
}

// =============================================================================
// Direct Audio: Playing Sound List + Mixer
// =============================================================================

#define MM_DIRECT_MAX_SOUNDS 8

typedef struct {
    s16* pcmData;    // Decoded PCM buffer (allocated, must be freed)
    u32 pcmLength;   // Total samples in buffer
    f32 pcmPosition; // Current fractional playback position
    f32 advance;     // Samples to advance per output sample (tuning * freqScale)
    f32 volume;      // Volume [0..1]
    f32 pan;         // Pan [0=left, 0.5=center, 1=right]
    u16 mmSfxId;     // MM SFX ID for stop/identify
    u8 active;       // 1=playing, 0=free
} MmPlayingSound;

static MmPlayingSound sPlayingSounds[MM_DIRECT_MAX_SOUNDS];

// Get SoundFontSound for an MM SFX ID (handles voice bank drum mapping)
static SoundFontSound* MmDirectAudio_GetSound(u16 mmSfxId) {
    SoundFont* font = MmSfx_GetFontForSfx(mmSfxId);
    if (!font)
        return nullptr;

    s32 bank = MM_SFX_BANK_INDEX(mmSfxId);
    s32 sfxIndex = MM_SFX_SOUND_INDEX(mmSfxId);

    // Voice bank (6) stores voices as drums in soundfont 0.
    // The drum index IS the SFX index directly (e.g., 0xC5 = drum 197 for Goron damage).
    if (bank == 6 && font->numDrums > 0) {
        MMSFX_LOG("[MmDirectAudio] Voice lookup: sfxId=0x%04X, sfxIndex=%d, numDrums=%u", mmSfxId, sfxIndex,
                  font->numDrums);

        if ((u32)sfxIndex >= font->numDrums || !font->drums || !font->drums[sfxIndex])
            return nullptr;
        return &font->drums[sfxIndex]->sound;
    }

    // Regular SFX bank - uses soundEffects[] array
    if ((u32)sfxIndex >= font->numSfx)
        return nullptr;
    return &font->soundEffects[sfxIndex];
}

// Start playing an MM sound
static void MmDirectAudio_Play(u16 mmSfxId, f32 freqScale) {
    SoundFontSound* sfxSound = MmDirectAudio_GetSound(mmSfxId);
    if (!sfxSound || !sfxSound->sample) {
        MMSFX_LOG("[MmDirectAudio] No sample for 0x%04X", mmSfxId);
        return;
    }

    u32 pcmLength = 0;
    s16* pcm = MmDirectAudio_DecodeADPCM(sfxSound->sample, &pcmLength);
    if (!pcm || pcmLength == 0) {
        MMSFX_LOG("[MmDirectAudio] Decode failed for 0x%04X", mmSfxId);
        return;
    }

    // Find free slot (or evict oldest)
    s32 freeSlot = -1;
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        if (!sPlayingSounds[i].active) {
            freeSlot = i;
            break;
        }
    }
    if (freeSlot < 0) {
        freeSlot = 0;
        if (sPlayingSounds[0].pcmData)
            free(sPlayingSounds[0].pcmData);
        sPlayingSounds[0].pcmData = nullptr;
        sPlayingSounds[0].active = 0;
    }

    MmPlayingSound* snd = &sPlayingSounds[freeSlot];
    if (snd->pcmData)
        free(snd->pcmData);

    snd->pcmData = pcm;
    snd->pcmLength = pcmLength;
    snd->pcmPosition = 0.0f;
    snd->advance = sfxSound->tuning * freqScale;
    snd->volume = 0.8f;
    snd->pan = 0.5f;
    snd->mmSfxId = mmSfxId;
    snd->active = 1;

    MMSFX_LOG("[MmDirectAudio] Playing 0x%04X: %u samples, tuning=%.3f, freq=%.3f, advance=%.3f, codec=%d, size=%u, "
              "order=%d, npred=%d",
              mmSfxId, pcmLength, sfxSound->tuning, freqScale, snd->advance, sfxSound->sample->codec,
              sfxSound->sample->size, sfxSound->sample->book ? sfxSound->sample->book->order : -1,
              sfxSound->sample->book ? sfxSound->sample->book->npredictors : -1);
}

// Mix all active MM sounds into the output buffer (called from audio thread)
// outBuf: interleaved stereo s16 [L0,R0,L1,R1,...], numSamples = stereo pairs
void MmDirectAudio_MixInto(s16* outBuf, u32 numSamples) {
    for (s32 slot = 0; slot < MM_DIRECT_MAX_SOUNDS; slot++) {
        MmPlayingSound* snd = &sPlayingSounds[slot];
        if (!snd->active || !snd->pcmData)
            continue;

        f32 volL = snd->volume * (1.0f - snd->pan);
        f32 volR = snd->volume * snd->pan;

        for (u32 i = 0; i < numSamples; i++) {
            u32 pos = (u32)snd->pcmPosition;
            if (pos >= snd->pcmLength - 1) {
                snd->active = 0;
                break;
            }

            // Linear interpolation between adjacent samples
            f32 frac = snd->pcmPosition - (f32)pos;
            f32 sample = snd->pcmData[pos] * (1.0f - frac) + snd->pcmData[pos + 1] * frac;

            s32 outL = outBuf[i * 2] + (s32)(sample * volL);
            s32 outR = outBuf[i * 2 + 1] + (s32)(sample * volR);

            if (outL > 32767)
                outL = 32767;
            if (outL < -32768)
                outL = -32768;
            if (outR > 32767)
                outR = 32767;
            if (outR < -32768)
                outR = -32768;

            outBuf[i * 2] = (s16)outL;
            outBuf[i * 2 + 1] = (s16)outR;

            snd->pcmPosition += snd->advance;
        }
    }
}

// Stop a specific MM sound
static void MmDirectAudio_StopById(u16 mmSfxId) {
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        if (sPlayingSounds[i].active && sPlayingSounds[i].mmSfxId == mmSfxId) {
            sPlayingSounds[i].active = 0;
        }
    }
}

// Stop all MM sounds and free PCM buffers
void MmDirectAudio_StopAll(void) {
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        sPlayingSounds[i].active = 0;
        if (sPlayingSounds[i].pcmData) {
            free(sPlayingSounds[i].pcmData);
            sPlayingSounds[i].pcmData = nullptr;
        }
    }
}

// =============================================================================
// MmSfx Public API (unchanged interface, new direct audio backend)
// =============================================================================

void MmSfx_PlayAtPos(u16 sfxId, Vec3f* pos) {
    MmSfx_PlayEx(sfxId, pos, 4, nullptr, nullptr, nullptr);
}

void MmSfx_PlayEx(u16 sfxId, Vec3f* pos, u8 token, f32* freqScale, f32* vol, s8* reverbAdd) {
    if (!MmAssets_IsAvailable())
        return;
    f32 freq = freqScale ? *freqScale : 1.0f;
    MmDirectAudio_Play(sfxId, freq);
}

void MmSfx_Stop(u16 sfxId) {
    MmDirectAudio_StopById(sfxId);
}

void MmSfx_PlayGoronRoll(Vec3f* pos, f32 speed) {
    sTempFreqScale = 0.8f + (speed / 20.0f) * 0.4f;
    if (sTempFreqScale > 1.5f)
        sTempFreqScale = 1.5f;
    if (sTempFreqScale < 0.5f)
        sTempFreqScale = 0.5f;
    MmSfx_PlayEx(MM_NA_SE_PL_GORON_ROLL, pos, 4, &sTempFreqScale, nullptr, nullptr);
}

void MmSfx_PlayGoronCharge(Vec3f* pos, f32 chargeLevel) {
    sTempFreqScale = 0.7f + chargeLevel * 0.6f;
    MmSfx_PlayEx(MM_NA_SE_PL_GORON_BALL_CHARGE, pos, 4, &sTempFreqScale, nullptr, nullptr);
}

void MmSfx_PlayTransformFlash(void) {
    MmSfx_PlayAtPos(MM_NA_SE_SY_TRANSFORM_MASK_FLASH, nullptr);
}

void MmSfx_GetCacheStats(s32* outLoadedFonts, s32* outTotalBytes) {
    if (outLoadedFonts)
        *outLoadedFonts = sSfxCacheCount;
    if (outTotalBytes) {
        size_t total = 0;
        for (s32 i = 0; i < sSfxCacheCount; i++)
            total += sSfxCache[i].sizeBytes;
        *outTotalBytes = (s32)total;
    }
}

void MmSfx_FlushCache(void) {
    for (s32 i = 0; i < MM_SFX_MAX_FONTS; i++) {
        sSfxCache[i].fontId = -1;
        sSfxCache[i].font = nullptr;
        sSfxCache[i].sizeBytes = 0;
    }
    sSfxCacheCount = 0;
}

